package com.xxl.job.admin.controller.interceptor;

import static org.mockito.Mockito.*;

import javax.servlet.http.Cookie;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import org.junit.Before;
import org.junit.Test;
import org.springframework.web.servlet.ModelAndView;

import java.util.Map;

public class CookieInterceptorTest {

    private HttpServletRequest request;
    private HttpServletResponse response;
    private Object handler;
    private ModelAndView modelAndView;
    private CookieInterceptor cookieInterceptor;

    @Before
    public void setUp() {
        request = mock(HttpServletRequest.class);
        response = mock(HttpServletResponse.class);
        handler = mock(Object.class);
        modelAndView = new ModelAndView();
        cookieInterceptor = new CookieInterceptor();
    }

    @Test
    public void testPostHandleWithCookies() throws Exception {
        // 创建模拟cookie
        Cookie cookie1 = new Cookie("name1", "value1");
        Cookie cookie2 = new Cookie("name2", "value2");
        Cookie[] cookies = new Cookie[]{cookie1, cookie2};

        // 配置HttpServletRequest返回模拟cookie
        when(request.getCookies()).thenReturn(cookies);

        // 调用postHandle方法
        cookieInterceptor.postHandle(request, response, handler, modelAndView);

        // 验证modelAndView是否包含cookieMap
        @SuppressWarnings("unchecked")
        Map<String, Cookie> cookieMap = (Map<String, Cookie>) modelAndView.getModel().get("cookieMap");
        assertNotNull("cookieMap should not be null", cookieMap);
        assertEquals("cookieMap should contain 2 cookies", 2, cookieMap.size());
        assertTrue("cookieMap should contain cookie with name 'name1'", cookieMap.containsKey("name1"));
        assertTrue("cookieMap should contain cookie with name 'name2'", cookieMap.containsKey("name2"));
    }

    @Test
    public void testPostHandleWithoutCookies() throws Exception {
        // 配置HttpServletRequest返回null cookies
        when(request.getCookies()).thenReturn(null);

        // 调用postHandle方法
        cookieInterceptor.postHandle(request, response, handler, modelAndView);

        // 验证modelAndView是否不包含cookieMap
        assertNull("cookieMap should be null when no cookies are present", modelAndView.getModel().get("cookieMap"));
    }

    // 你可以继续添加更多测试用例以测试其他方面，例如检查I18nUtil静态方法的添加等。
}

