import org.mockito.MockedStatic;
import org.mockito.Mockito;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.ArgumentMatchers.anyString;

class LocalCacheUtilTest {

    private MockedStatic<LocalCacheUtil> mockedLocalCacheUtil;

    @BeforeEach
    void setUp() {
        mockedLocalCacheUtil = Mockito.mockStatic(LocalCacheUtil.class, Mockito.CALLS_REAL_METHODS);
    }

    @Test
    void testGetWithValidKey() {
        // Arrange: 设置一个有效键值对，其中值为"testValue"，并且未过期
        String key = "validKey";
        Object expectedValue = "testValue";
        LocalCacheData mockLocalCacheData = new LocalCacheData(expectedValue, System.currentTimeMillis() + 10000); // 10秒后过期

        // 使用Mockito模拟cacheRepository的行为
        mockedLocalCacheUtil.when(() -> LocalCacheUtil.get(anyString())).thenReturn(mockLocalCacheData);

        // Act: 调用get方法
        Object actualValue = LocalCacheUtil.get(key);

        // Assert: 验证获取的值是否正确
        assertEquals(expectedValue, actualValue);
    }

    @Test
    void testGetWithNullKey() {
        // Arrange: 传入null作为键
        String key = null;

        // Act: 调用get方法
        Object actualValue = LocalCacheUtil.get(key);

        // Assert: 验证返回值是否为null，因为null键是不被接受的
        assertNull(actualValue);
    }

    @Test
    void testGetWithEmptyKey() {
        // Arrange: 传入空字符串作为键
        String key = "";

        // Act: 调用get方法
        Object actualValue = LocalCacheUtil.get(key);

        // Assert: 验证返回值是否为null，因为空字符串键是不被接受的
        assertNull(actualValue);
    }

    @Test
    void testGetWithExpiredKey() {
        // Arrange: 设置一个已过期的键值对
        String key = "expiredKey";
        Object expectedValue = "expiredValue";
        LocalCacheData mockLocalCacheData = new LocalCacheData(expectedValue, System.currentTimeMillis() - 10000); // 已过期

        // 使用Mockito模拟cacheRepository的行为
        mockedLocalCacheUtil.when(() -> LocalCacheUtil.get(anyString())).thenReturn(mockLocalCacheData);

        // Act: 调用get方法
        Object actualValue = LocalCacheUtil.get(key);

        // Assert: 验证返回值是否为null，因为键已经过期
        assertNull(actualValue);
    }

    // 在这里可以添加更多测试用例...

    // 清理资源
    @AfterEach
    void tearDown() {
        mockedLocalCacheUtil.close();
    }
}

